import { PointsDetailProps } from '../../../src/screens/PointsDetail/Models';
import {
  getDetailScreenTitle,
  getPurchaseTypeLabel,
  getTagSubType,
  getTransactionGainType,
  getVehicleInfo,
} from '../../../src/screens/PointsDetail/utils';

describe('PointsDetail Utils', () => {
  describe('getTransactionGainType', () => {
    it('should return TAG when icon contains tag indicator', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Test',
        type: 'RECEIVED',
        amount: 100,
        currencyValue: 10,
        icon: 'icon-tag-test',
        details: {
          provider: '',
          extraInfo: '',
          fields: [],
        },
      };

      expect(getTransactionGainType(transaction)).toBe('TAG');
    });

    it('should return TAG when description contains tag indicator', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Pedágio test',
        type: 'RECEIVED',
        amount: 100,
        currencyValue: 10,
        icon: 'icon-test',
        details: {
          provider: '',
          extraInfo: '',
          fields: [],
        },
      };

      expect(getTransactionGainType(transaction)).toBe('TAG');
    });

    it('should return TAG when provider contains tag indicator', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Test',
        type: 'RECEIVED',
        amount: 100,
        currencyValue: 10,
        icon: 'icon-test',
        details: {
          provider: 'estacionamento',
          extraInfo: '',
          fields: [],
        },
      };

      expect(getTransactionGainType(transaction)).toBe('TAG');
    });

    it('should return CASHBACK when provider contains cashback', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Cashback resgatado',
        type: 'DEBIT',
        amount: -500,
        currencyValue: 2996,
        icon: 'icon-tag',
        details: {
          provider: 'Cashback resgatado',
          extraInfo: 'Resgate de cashback em fatura',
          fields: [],
        },
      };

      expect(getTransactionGainType(transaction)).toBe('CASHBACK');
    });

    it('should return CASHBACK when provider contains cashback (case insensitive)', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Test',
        type: 'DEBIT',
        amount: -500,
        currencyValue: 2996,
        icon: 'icon-tag',
        details: {
          provider: 'CASHBACK RESGATADO',
          extraInfo: '',
          fields: [],
